@'
const { app, BrowserWindow, Tray, Menu, screen, nativeImage, ipcMain, globalShortcut, dialog } = require("electron");
const path = require("path");
const fs = require("fs");

let win = null;
let tray = null;
let muted = false;
let uiohookStarted = false;
let voiceActive = false;
let stressTestResults = [];
let gameControlActive = false;

const ICON_PATH = path.join(__dirname, "build", "icon.png");

function log(level, msg) {
  const ts = new Date().toISOString();
  const line = "[" + ts + "] [" + level + "] " + msg;
  console.log(line);
  try { fs.appendFileSync(path.join(__dirname, "pet.log"), line + "\n"); } catch (_) {}
}

function createWindow() {
  const { width, height } = screen.getPrimaryDisplay().workAreaSize;
  win = new BrowserWindow({
    width, height, x: 0, y: 0,
    frame: false, transparent: true, alwaysOnTop: true,
    hasShadow: false, resizable: false, movable: false,
    skipTaskbar: true, focusable: true, fullscreenable: false,
    backgroundColor: "#00000000", icon: ICON_PATH,
    webPreferences: {
      preload: path.join(__dirname, "preload.js"),
      contextIsolation: true, nodeIntegration: false, sandbox: false,
    },
  });
  win.setVisibleOnAllWorkspaces(true, { visibleOnFullScreen: false });
  win.setAlwaysOnTop(true, "screen-saver");
  win.setIgnoreMouseEvents(true, { forward: true });
  win.loadFile("index.html");
  win.webContents.on("did-finish-load", () => log("INFO", "Renderer loaded ok"));
}

function registerIpcHandlers() {
  ipcMain.on("set-ignore-mouse", (_e, ignore) => {
    if (!win) return;
    if (ignore) win.setIgnoreMouseEvents(true, { forward: true });
    else win.setIgnoreMouseEvents(false);
  });
  ipcMain.handle("get-muted", () => muted);
  ipcMain.on("toggle-mute", () => {
    muted = !muted;
    if (win && !win.isDestroyed()) win.webContents.send("set-muted", muted);
  });
  ipcMain.handle("voice-status", () => ({ active: voiceActive }));
  ipcMain.on("voice-command-from-renderer", (_e, cmd) => {
    log("VOICE", "Command: " + cmd);
    if (win && !win.isDestroyed()) win.webContents.send("voice-command", cmd);
  });
  ipcMain.handle("game-control", async (_e, cmd) => {
    gameControlActive = true;
    log("GAME", "Control: " + JSON.stringify(cmd));
    try {
      const robot = require("robotjs");
      switch (cmd.type) {
        case "key": robot.keyTap(cmd.key); break;
        case "keyToggle": robot.keyToggle(cmd.key, cmd.down ? "down" : "up"); break;
        case "mouseMove": robot.moveMouse(cmd.x, cmd.y); break;
        case "mouseClick": robot.mouseClick(cmd.button || "left"); break;
        case "type": robot.typeString(cmd.text); break;
        default: return { ok: false, error: "Unknown cmd: " + cmd.type };
      }
      return { ok: true };
    } catch (err) { return { ok: false, error: err.message }; }
  });
  ipcMain.handle("stress-test", async (_e, config) => {
    const results = [];
    const t0 = Date.now();
    log("STRESS", "Start: " + JSON.stringify(config));
    if (config.cpu) {
      const t1 = Date.now();
      let s = 0;
      for (let i = 0; i < (config.iterations || 50000); i++) s += Math.sqrt(i);
      results.push({ type: "cpu", ms: Date.now() - t1, n: config.iterations || 50000 });
    }
    if (config.memory) {
      const t1 = Date.now();
      const a = new Array(config.memSize || 50000).fill(0).map((_, i) => i).sort((a, b) => b - a);
      results.push({ type: "memory", ms: Date.now() - t1, size: a.length });
    }
    if (config.render && win && !win.isDestroyed()) {
      win.webContents.send("stress-render", config);
      results.push({ type: "render", status: "triggered" });
    }
    stressTestResults = results;
    log("STRESS", "Done in " + (Date.now() - t0) + "ms");
    return { ok: true, results, totalMs: Date.now() - t0 };
  });
  ipcMain.handle("stress-results", () => stressTestResults);
  ipcMain.handle("system-info", () => ({
    platform: process.platform, arch: process.arch, node: process.version,
    electron: process.versions.electron, memory: process.memoryUsage(), uptime: process.uptime(),
  }));
  ipcMain.handle("get-logs", () => {
    try { return fs.readFileSync(path.join(__dirname, "pet.log"), "utf-8"); }
    catch (_) { return ""; }
  });
}

function startGlobalKeyHook() {
  try {
    const { uIOhook } = require("uiohook-napi");
    uIOhook.on("keydown", (e) => {
      if (win && !win.isDestroyed()) win.webContents.send("global-keystroke", {
        keycode: e.keycode, altKey: e.altKey, ctrlKey: e.ctrlKey, shiftKey: e.shiftKey
      });
    });
    uIOhook.start();
    uiohookStarted = true;
    log("INFO", "Keyboard hook started");
  } catch (err) { log("ERROR", "Keyboard hook failed: " + err.message); }
}

function registerShortcuts() {
  globalShortcut.register("CommandOrControl+Shift+V", () => {
    voiceActive = !voiceActive;
    if (win && !win.isDestroyed()) win.webContents.send("voice-toggle", voiceActive);
  });
  globalShortcut.register("CommandOrControl+Shift+G", () => {
    gameControlActive = !gameControlActive;
    if (win && !win.isDestroyed()) win.webContents.send("game-mode-toggle", gameControlActive);
  });
  globalShortcut.register("CommandOrControl+Shift+T", () => {
    if (win && !win.isDestroyed()) win.webContents.send("trigger-stress-test");
  });
}

function buildTrayMenu() {
  return Menu.buildFromTemplate([
    { label: "显示/隐藏", click: () => { if (win) win.isVisible() ? win.hide() : win.show(); } },
    { label: "静音", type: "checkbox", checked: muted,
      click: (item) => { muted = item.checked; if (win && !win.isDestroyed()) win.webContents.send("set-muted", muted); } },
    { type: "separator" },
    { label: "语音控制", type: "checkbox", checked: voiceActive,
      click: (item) => { voiceActive = item.checked; if (win && !win.isDestroyed()) win.webContents.send("voice-toggle", voiceActive); } },
    { label: "游戏模式", type: "checkbox", checked: gameControlActive,
      click: (item) => { gameControlActive = item.checked; if (win && !win.isDestroyed()) win.webContents.send("game-mode-toggle", gameControlActive); } },
    { type: "separator" },
    { label: "运行压力测试", click: () => { if (win && !win.isDestroyed()) win.webContents.send("trigger-stress-test"); } },
    { label: "查看日志", click: () => {
      const lp = path.join(__dirname, "pet.log");
      const msg = fs.existsSync(lp) ? fs.readFileSync(lp, "utf-8").slice(-5000) : "暂无日志";
      dialog.showMessageBox(win, { type: "info", title: "日志", message: msg });
    }},
    { type: "separator" },
    { label: "退出", role: "quit" },
  ]);
}

function createTray() {
  let trayImg = nativeImage.createFromPath(ICON_PATH);
  if (!trayImg.isEmpty()) trayImg = trayImg.resize({ width: 18, height: 18 });
  tray = new Tray(trayImg.isEmpty() ? nativeImage.createEmpty() : trayImg);
  if (trayImg.isEmpty()) tray.setTitle("🐱");
  tray.setToolTip("小土豆桌宠 AI助手");
  tray.setContextMenu(buildTrayMenu());
}

app.whenReady().then(() => {
  log("INFO", "=== 小土豆桌宠启动 ===");
  if (process.platform === "darwin" && app.dock) app.dock.hide();
  registerIpcHandlers();
  createWindow();
  createTray();
  startGlobalKeyHook();
  try { registerShortcuts(); } catch (e) { log("WARN", "Shortcut fail: " + e.message); }
  log("INFO", "启动完成!");
});

app.on("window-all-closed", (e) => e.preventDefault());
app.on("before-quit", () => {
  globalShortcut.unregisterAll();
  if (uiohookStarted) try { require("uiohook-napi").uIOhook.stop(); } catch (_) {}
});
