const { contextBridge, ipcRenderer } = require("electron");

// ====================== 完整桥接API ======================
contextBridge.exposeInMainWorld("pet", {
  // ---- 基础 ----
  setIgnoreMouse: (ignore) => ipcRenderer.send("set-ignore-mouse", ignore),
  onKeystroke: (cb) => {
    ipcRenderer.on("global-keystroke", (_e, data) => cb(data));
  },
  onMutedChange: (cb) => ipcRenderer.on("set-muted", (_e, v) => cb(v)),
  getMuted: () => ipcRenderer.invoke("get-muted"),
  toggleMute: () => ipcRenderer.send("toggle-mute"),

  // ---- 语音 ----
  voiceStatus: () => ipcRenderer.invoke("voice-status"),
  onVoiceToggle: (cb) => ipcRenderer.on("voice-toggle", (_e, v) => cb(v)),
  sendVoiceCommand: (cmd) => ipcRenderer.send("voice-command-from-renderer", cmd),
  onVoiceCommand: (cb) => ipcRenderer.on("voice-command", (_e, cmd) => cb(cmd)),

  // ---- 游戏操控 ----
  gameControl: (cmd) => ipcRenderer.invoke("game-control", cmd),
  onGameModeToggle: (cb) => ipcRenderer.on("game-mode-toggle", (_e, v) => cb(v)),

  // ---- 压力测试 ----
  runStressTest: (config) => ipcRenderer.invoke("stress-test", config),
  getStressResults: () => ipcRenderer.invoke("stress-results"),
  onStressRender: (cb) => ipcRenderer.on("stress-render", (_e, cfg) => cb(cfg)),
  onTriggerStressTest: (cb) => ipcRenderer.on("trigger-stress-test", () => cb()),

  // ---- 系统 ----
  getSystemInfo: () => ipcRenderer.invoke("system-info"),
  getLogs: () => ipcRenderer.invoke("get-logs"),
});
