@'
/* ================================================================
   小土豆AI桌宠 - 增强版渲染器
   功能: 3D猫咪 + 语音识别 + 语音合成 + AI对话 + 游戏操控 + 压力测试
   ================================================================ */

import * as THREE from "three";
import { GLTFLoader } from "three/addons/loaders/GLTFLoader.js";

const canvas = document.getElementById("c");
const audio = document.getElementById("spin-audio");

let W = window.innerWidth;
let H = window.innerHeight;

const renderer = new THREE.WebGLRenderer({ canvas, alpha: true, antialias: true });
renderer.setPixelRatio(window.devicePixelRatio);
renderer.setSize(W, H, false);
renderer.setClearColor(0x000000, 0);

const scene = new THREE.Scene();
const camera = new THREE.OrthographicCamera(0, W, H, 0, -2000, 2000);
camera.position.set(0, 0, 500);
camera.lookAt(0, 0, 0);

scene.add(new THREE.AmbientLight(0xffffff, 0.85));
const key = new THREE.DirectionalLight(0xffffff, 0.9);
key.position.set(200, 400, 300);
scene.add(key);

const pivot = new THREE.Group();
pivot.position.set(W * 0.5, 140, 0);
scene.add(pivot);

const facing = new THREE.Group();
pivot.add(facing);

const bob = new THREE.Group();
facing.add(bob);

const state = {
  cat: null, mixer: null, spinAction: null, walkAction: null, idleAction: null,
  catHalfWidth: 80, catHeight: 240,
  mode: "idle", modeUntil: 0, walkTarget: W * 0.5, facingDir: 1,
  hover: false, dragging: false, dragOffset: { x: 0, y: 0 }, movedDuringDrag: false,
  happiness: 1.0, cursor: { x: W / 2, y: H / 2 }, muted: false,
  typing: { active: false, lastKey: 0, rate: 0, endsAt: 0 },
  // 新增状态
  voiceEnabled: false, gameMode: false, voiceListening: false,
  aiResponses: [], speechBubble: null, speechTimer: 0,
  stressActive: false, stressParticles: [],
};

// ====================== 语音识别 ======================
let recognition = null;
function initVoiceRecognition() {
  const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
  if (!SpeechRecognition) return;
  recognition = new SpeechRecognition();
  recognition.continuous = true;
  recognition.interimResults = false;
  recognition.lang = "zh-CN";
  recognition.onresult = (event) => {
    const last = event.results[event.results.length - 1];
    if (last.isFinal) {
      const text = last[0].transcript.trim();
      processVoiceCommand(text);
    }
  };
  recognition.onerror = () => { if (state.voiceEnabled && state.voiceListening) recognition.start(); };
  recognition.onend = () => { if (state.voiceEnabled && state.voiceListening) recognition.start(); };
}

function processVoiceCommand(text) {
  console.log("🎤 Voice:", text);
  showSpeechBubble(text, "#4ade80");

  // 语音命令解析
  const cmd = text.toLowerCase();
  if (cmd.includes("跳") || cmd.includes("转圈") || cmd.includes("spin")) triggerSpin();
  else if (cmd.includes("过来") || cmd.includes("过来呀")) { state.mode = "walk"; state.walkTarget = state.cursor.x; state.facingDir = state.cursor.x < pivot.position.x ? -1 : 1; state.modeUntil = performance.now() + 4000; }
  else if (cmd.includes("坐下") || cmd.includes("sit")) { state.mode = "sit"; state.modeUntil = performance.now() + 3000; }
  else if (cmd.includes("你好") || cmd.includes("hello")) { speak("你好呀！我是小土豆！"); showSpeechBubble("你好呀！🐱", "#fbbf24"); }
  else if (cmd.includes("游戏") || cmd.includes("game")) { state.gameMode = !state.gameMode; pet.gameControl({ type: "key", key: "escape" }); speak(state.gameMode ? "游戏模式已开启" : "游戏模式已关闭"); }
  else if (cmd.includes("测试") || cmd.includes("stress")) startStressTest();
  else if (cmd.includes("日志") || cmd.includes("log")) showLogDialog();
  else { speak("收到: " + text); aiRespond(text); }
}

// ====================== AI 对话 ======================
async function aiRespond(userText) {
  showSpeechBubble("思考中...", "#60a5fa");
  const apiKey = localStorage.getItem("deepseek_api_key") || "";
  const model = "deepseek-chat"; // 正确的模型名！
  try {
    const resp = await fetch("https://api.deepseek.com/v1/chat/completions", {
      method: "POST",
      headers: { "Content-Type": "application/json", "Authorization": "Bearer " + apiKey },
      body: JSON.stringify({
        model: model,
        messages: [
          { role: "system", content: "你是一只可爱的3D桌面猫咪宠物'小土豆'，用简短可爱的中文回答，不超过50字，可以加emoji。" },
          { role: "user", content: userText }
        ],
        max_tokens: 100,
        temperature: 0.8
      })
    });
    if (!resp.ok) throw new Error("API error: " + resp.status);
    const data = await resp.json();
    const reply = data.choices[0].message.content;
    showSpeechBubble(reply, "#fbbf24");
    speak(reply);
    bumpHappiness(0.1);
  } catch (err) {
    console.error("AI error:", err);
    showSpeechBubble("唔...网络好像不太好 😿", "#f87171");
  }
}

// ====================== 语音合成 ======================
function speak(text) {
  if (state.muted) return;
  if (!window.speechSynthesis) return;
  const u = new SpeechSynthesisUtterance(text);
  u.lang = "zh-CN";
  u.rate = 1.1;
  u.pitch = 1.2;
  u.volume = 0.8;
  window.speechSynthesis.cancel();
  window.speechSynthesis.speak(u);
}

// ====================== 气泡文字 ======================
let bubbleEl = null;
function showSpeechBubble(text, color) {
  if (!bubbleEl) {
    bubbleEl = document.createElement("div");
    bubbleEl.style.cssText = "position:fixed;top:20px;left:50%;transform:translateX(-50%);padding:10px 20px;border-radius:20px;font-size:18px;font-family:sans-serif;z-index:9999;pointer-events:none;transition:opacity 0.3s;white-space:nowrap;max-width:80vw;text-align:center;text-shadow:0 1px 2px rgba(0,0,0,0.5);color:#fff;";
    document.body.appendChild(bubbleEl);
  }
  bubbleEl.style.background = color;
  bubbleEl.style.opacity = "1";
  bubbleEl.textContent = text;
  state.speechTimer = performance.now() + 4000;
}

function updateSpeechBubble(now) {
  if (bubbleEl && now > state.speechTimer) {
    bubbleEl.style.opacity = "0";
  }
}

// ====================== 压力测试 ======================
async function startStressTest() {
  state.stressActive = true;
  state.stressParticles = [];
  for (let i = 0; i < 50; i++) {
    state.stressParticles.push({
      x: Math.random() * W, y: Math.random() * H,
      vx: (Math.random() - 0.5) * 4, vy: (Math.random() - 0.5) * 4,
      size: Math.random() * 8 + 2, color: ["#fbbf24","#f87171","#4ade80","#60a5fa"][Math.floor(Math.random()*4)]
    });
  }
  showSpeechBubble("🔬 压力测试开始...", "#fbbf24");
  const result = await pet.runStressTest({ cpu: true, memory: true, render: true, iterations: 100000, memSize: 100000 });
  showSpeechBubble("✅ 测试完成! CPU:" + (result.results[0]?.ms || "?") + "ms", "#4ade80");
  setTimeout(() => { state.stressActive = false; state.stressParticles = []; }, 3000);
}

async function showLogDialog() {
  const logs = await pet.getLogs();
  alert("最近日志:\n" + (logs.slice(-2000) || "无"));
}

// ====================== 事件监听 ======================
window.pet.getMuted().then((m) => { state.muted = !!m; });
window.pet.onMutedChange((m) => { state.muted = !!m; if (state.muted) try { audio.pause(); } catch (_) {} });
window.pet.onKeystroke(() => {
  const now = performance.now();
  const dt = state.typing.lastKey ? (now - state.typing.lastKey) / 1000 : 0.2;
  state.typing.lastKey = now;
  const inst = dt > 0 ? Math.min(1 / dt, 20) : 10;
  state.typing.rate = state.typing.rate * 0.6 + inst * 0.4;
  state.typing.active = true;
  state.typing.endsAt = now + 1200;
  bumpHappiness(0.005);
});
window.pet.onVoiceToggle((v) => {
  state.voiceEnabled = v;
  if (v) { state.voiceListening = true; if (recognition) recognition.start(); }
  else { state.voiceListening = false; if (recognition) recognition.stop(); }
  showSpeechBubble(v ? "🎤 语音已开启" : "🔇 语音已关闭", v ? "#4ade80" : "#f87171");
});
window.pet.onGameModeToggle((v) => {
  state.gameMode = v;
  showSpeechBubble(v ? "🎮 游戏模式开启" : "🎮 游戏模式关闭", v ? "#fbbf24" : "#9ca3af");
});
window.pet.onTriggerStressTest(() => startStressTest());

// ====================== 模型加载 ======================
const MODEL_PATH = "assets/monochrome-muse/model_walking.glb";
const FALLBACK_PATH = "assets/cat/scene.gltf";
const MODEL_HEIGHT = 240;
const loader = new GLTFLoader();

function onLoad(gltf) {
  const cat = gltf.scene;
  const box = new THREE.Box3().setFromObject(cat);
  const size = new THREE.Vector3();
  box.getSize(size);
  const scale = MODEL_HEIGHT / size.y;
  cat.scale.setScalar(scale);

  const box2 = new THREE.Box3().setFromObject(cat);
  const center = new THREE.Vector3();
  box2.getCenter(center);
  cat.position.x -= center.x;
  cat.position.y -= box2.min.y;
  cat.position.z -= center.z;

  state.catHalfWidth = (box2.max.x - box2.min.x) / 2 + 12;
  state.catHeight = box2.max.y - box2.min.y;

  cat.traverse((o) => {
    if (o.isMesh && o.material.color) o.userData.baseColor = o.material.color.clone();
  });

  bob.add(cat);
  state.cat = cat;

  if (gltf.animations && gltf.animations.length) {
    state.mixer = new THREE.AnimationMixer(cat);
    const walkClip = gltf.animations.find(a => a.name.toLowerCase().includes("walk") || a.name.toLowerCase().includes("run")) || gltf.animations[0];
    state.spinAction = state.mixer.clipAction(walkClip);
    state.spinAction.setLoop(THREE.LoopRepeat);
    state.spinAction.timeScale = 1.0;
    state.spinAction.enabled = false;
    state.walkAction = state.mixer.clipAction(walkClip);
    state.walkAction.setLoop(THREE.LoopRepeat);
    const idleClip = gltf.animations.find(a => a.name.toLowerCase().includes("idle") || a.name.toLowerCase().includes("stand"));
    if (idleClip) { state.idleAction = state.mixer.clipAction(idleClip); state.idleAction.setLoop(THREE.LoopRepeat); }
  }
  scheduleNextMode(0);
}

loader.load(MODEL_PATH, onLoad, undefined, () => {
  console.warn("Fallback to cat model");
  loader.load(FALLBACK_PATH, onLoad);
});

function scheduleNextMode(now) {
  if (state.mode === "spin") return;
  const r = Math.random();
  if (r < 0.45) { state.mode = "idle"; state.modeUntil = now + 2000 + Math.random() * 3000; }
  else if (r < 0.8) { state.mode = "walk"; state.walkTarget = 60 + Math.random() * (W - 120); state.facingDir = state.walkTarget < pivot.position.x ? -1 : 1; state.modeUntil = now + 6000 + Math.random() * 4000; }
  else if (r < 0.92) { state.mode = "sit"; state.modeUntil = now + 2500 + Math.random() * 2500; }
  else { state.mode = "yawn"; state.modeUntil = now + 1200 + Math.random() * 800; }
}

// ====================== 输入处理 ======================
window.addEventListener("mousemove", (e) => {
  state.cursor.x = e.clientX; state.cursor.y = e.clientY;
  if (state.dragging) {
    pivot.position.x = clamp(e.clientX - state.dragOffset.x, 60, W - 60);
    pivot.position.y = clamp((H - e.clientY) - state.dragOffset.y, 20, H - state.catHeight);
    state.movedDuringDrag = true;
    return;
  }
  updateHoverState();
});
window.addEventListener("mousedown", (e) => {
  if (!state.hover) return;
  state.dragging = true; state.movedDuringDrag = false;
  state.dragOffset.x = e.clientX - pivot.position.x;
  state.dragOffset.y = (H - e.clientY) - pivot.position.y;
  state.mode = "idle"; state.modeUntil = performance.now() + 1500;
});
window.addEventListener("mouseup", () => {
  if (!state.dragging) return;
  state.dragging = false;
  if (!state.movedDuringDrag) triggerSpin(); else bumpHappiness(0.05);
});
window.addEventListener("resize", () => {
  W = window.innerWidth; H = window.innerHeight;
  renderer.setSize(W, H, false);
  camera.left = 0; camera.right = W; camera.top = H; camera.bottom = 0;
  camera.updateProjectionMatrix();
});

function updateHoverState() {
  const sx = pivot.position.x;
  const syFromBottom = pivot.position.y;
  const syFromTop = H - syFromBottom;
  const over = state.cursor.x >= sx - state.catHalfWidth && state.cursor.x <= sx + state.catHalfWidth &&
    state.cursor.y >= syFromTop - state.catHeight && state.cursor.y <= syFromTop + 10;
  if (over !== state.hover) { state.hover = over; pet.setIgnoreMouse(!over); }
}

function triggerSpin() {
  if (!state.spinAction) return;
  state.mode = "spin"; state.modeUntil = performance.now() + 3200;
  state.spinAction.reset(); state.spinAction.enabled = true; state.spinAction.play();
  if (!state.muted) { try { audio.loop = false; audio.playbackRate = 1.0; audio.currentTime = 0; audio.play().catch(() => {}); } catch (_) {} }
  bumpHappiness(0.25);
}

function bumpHappiness(d) { state.happiness = clamp(state.happiness + d, 0, 1); applyMood(); }
function applyMood() {
  const h = state.happiness;
  canvas.style.filter = "saturate(" + (0.35 + 0.95 * h) + ") brightness(" + (0.85 + 0.25 * h) + ")";
}

// ====================== 渲染循环 ======================
const clock = new THREE.Clock();
let lastHappinessDecay = performance.now();

function tick() {
  const now = performance.now();
  const dt = clock.getDelta();

  if (now - lastHappinessDecay > 1000) { lastHappinessDecay = now; state.happiness = Math.max(0, state.happiness - 0.01); applyMood(); }

  // 打字动画
  if (state.typing.active && state.mode !== "spin" && state.spinAction) {
    const ts = clamp(0.6 + state.typing.rate * 0.5, 0.6, 4.5);
    state.spinAction.timeScale = ts;
    if (!state.spinAction.isRunning()) { state.spinAction.reset(); state.spinAction.enabled = true; state.spinAction.play(); }
    if (!state.muted) {
      try {
        if (audio.paused) { audio.loop = true; audio.currentTime = 0; audio.play().catch(() => {}); }
        audio.playbackRate = clamp(0.5 + state.typing.rate * 0.1, 0.5, 1.0);
      } catch (_) {}
    }
    bob.position.y = 0; bob.scale.set(1, 1, 1);
    if (now >= state.typing.endsAt) {
      state.typing.active = false; state.typing.rate = 0;
      state.spinAction.stop(); state.spinAction.enabled = false; state.spinAction.timeScale = 1.0;
      try { audio.pause(); audio.loop = false; audio.playbackRate = 1.0; } catch (_) {}
      scheduleNextMode(now);
    }
  } else { state.typing.rate *= 0.985; }

  if (state.mixer) state.mixer.update(dt);

  // 模式行为
  if (state.mode === "walk") {
    const dx = state.walkTarget - pivot.position.x;
    state.facingDir = Math.sign(dx) || state.facingDir;
    const speed = 60 * dt;
    if (Math.abs(dx) > 2) { pivot.position.x += Math.sign(dx) * Math.min(Math.abs(dx), speed); bob.position.y = Math.abs(Math.sin(now / 120)) * 6; }
    else bob.position.y = 0;
    if (now >= state.modeUntil || Math.abs(dx) < 2) scheduleNextMode(now);
  } else if (state.mode === "idle") {
    bob.position.y = Math.sin(now / 700) * 2.5;
    bob.scale.set(1, 1 + Math.sin(now / 700) * 0.015, 1);
    if (now >= state.modeUntil) scheduleNextMode(now);
  } else if (state.mode === "sit") {
    bob.position.y = 0; bob.scale.set(1, 0.95, 1);
    if (now >= state.modeUntil) { bob.scale.set(1, 1, 1); scheduleNextMode(now); }
  } else if (state.mode === "yawn") {
    const t = 1 - (state.modeUntil - now) / 2000;
    bob.scale.set(1, 1 + Math.sin(Math.min(1, t) * Math.PI) * 0.08, 1);
    if (now >= state.modeUntil) { bob.scale.set(1, 1, 1); scheduleNextMode(now); }
  } else if (state.mode === "spin") {
    if (now >= state.modeUntil) { state.spinAction.stop(); state.spinAction.enabled = false; try { audio.pause(); } catch (_) {} scheduleNextMode(now); }
  }

  state.facing.scaleX = facing.scale.x;
  facing.scale.x += (state.facingDir >= 0 ? 1 : -1 - facing.scale.x) * Math.min(1, dt * 8);

  if (state.cat && state.mode !== "spin") {
    const dx = state.cursor.x - pivot.position.x;
    const target = state.hover ? clamp(dx / 200, -0.6, 0.6) : 0;
    state.cat.rotation.y += (target - state.cat.rotation.y) * Math.min(1, dt * 4);
  }

  updateHoverState();
  updateSpeechBubble(now);

  // 压力测试粒子
  if (state.stressActive && state.stressParticles.length > 0) {
    // 动态效果透过canvas filter实现
    const intensity = Math.sin(now / 200) * 0.3 + 0.7;
    canvas.style.filter = "saturate(" + intensity + ") brightness(" + (1 + (1-intensity)*0.5) + ") hue-rotate(" + Math.sin(now/300)*10 + "deg)";
  }

  renderer.render(scene, camera);
  requestAnimationFrame(tick);
}

// ====================== 初始化 ======================
initVoiceRecognition();
tick();
applyMood();

function clamp(v, lo, hi) { return Math.max(lo, Math.min(hi, v)); }

