/* ================================================================
   小土豆AI桌宠 - 内置几何体猫咪 (零外部模型依赖)
   3D猫咪: Three.js 纯几何体 + 语音识别 + AI对话 + 游戏操控
   ================================================================ */

import * as THREE from "three";

const canvas = document.getElementById("c");
const audio = document.getElementById("spin-audio");
const bubbleEl = document.getElementById("bubble");
const loadingEl = document.getElementById("loading");

let W = window.innerWidth;
let H = window.innerHeight;

const renderer = new THREE.WebGLRenderer({ canvas, alpha: true, antialias: true });
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
renderer.setSize(W, H, false);
renderer.setClearColor(0x000000, 0);

const scene = new THREE.Scene();
const camera = new THREE.OrthographicCamera(0, W, H, 0, -2000, 2000);
camera.position.set(0, 0, 500);
camera.lookAt(0, 0, 0);

scene.add(new THREE.AmbientLight(0xffffff, 0.9));
const dLight = new THREE.DirectionalLight(0xffffff, 0.9);
dLight.position.set(200, 400, 300);
scene.add(dLight);

const pivot = new THREE.Group();
pivot.position.set(W * 0.5, H * 0.5, 0);
scene.add(pivot);

const facing = new THREE.Group();
pivot.add(facing);
const bob = new THREE.Group();
facing.add(bob);

// ====================== 用几何体建猫咪 ======================
function buildCat() {
  const catGroup = new THREE.Group();

  // 材质
  const furMat = new THREE.MeshStandardMaterial({ color: 0xff8c42, roughness: 0.6, metalness: 0.0 });
  const bellyMat = new THREE.MeshStandardMaterial({ color: 0xffecd2, roughness: 0.7 });
  const earInnerMat = new THREE.MeshStandardMaterial({ color: 0xffaa88, roughness: 0.5 });
  const eyeMat = new THREE.MeshStandardMaterial({ color: 0x111111, roughness: 0.1 });
  const eyeWhiteMat = new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.1 });
  const noseMat = new THREE.MeshStandardMaterial({ color: 0xff6688, roughness: 0.3 });
  const pawMat = new THREE.MeshStandardMaterial({ color: 0xffecd2, roughness: 0.5 });
  const tailMat = new THREE.MeshStandardMaterial({ color: 0xff7b32, roughness: 0.6 });
  const mouthMat = new THREE.MeshStandardMaterial({ color: 0x553322, roughness: 0.3 });

  // 身体 (椭圆球)
  const bodyGeo = new THREE.SphereGeometry(1, 32, 24);
  const body = new THREE.Mesh(bodyGeo, furMat);
  body.scale.set(1.0, 0.75, 0.7);
  body.position.y = 0.0;
  catGroup.add(body);

  // 肚皮
  const bellyGeo = new THREE.SphereGeometry(0.7, 32, 24);
  const belly = new THREE.Mesh(bellyGeo, bellyMat);
  belly.scale.set(0.9, 0.6, 0.5);
  belly.position.set(0, -0.15, 0.45);
  catGroup.add(belly);

  // 头
  const headGeo = new THREE.SphereGeometry(0.7, 32, 24);
  const head = new THREE.Mesh(headGeo, furMat);
  head.position.set(0, 0.85, 0.1);
  head.name = "head";
  catGroup.add(head);

  // 脸颊白色
  const cheekGeo = new THREE.SphereGeometry(0.35, 16, 12);
  const leftCheek = new THREE.Mesh(cheekGeo, bellyMat);
  leftCheek.position.set(-0.45, 0.7, 0.55);
  leftCheek.scale.set(0.7, 0.6, 0.3);
  catGroup.add(leftCheek);
  const rightCheek = new THREE.Mesh(cheekGeo, bellyMat);
  rightCheek.position.set(0.45, 0.7, 0.55);
  rightCheek.scale.set(0.7, 0.6, 0.3);
  catGroup.add(rightCheek);

  // 耳朵
  const earGeo = new THREE.ConeGeometry(0.3, 0.55, 8);
  const leftEar = new THREE.Mesh(earGeo, furMat);
  leftEar.position.set(-0.35, 1.35, 0.1);
  leftEar.rotation.z = 0.25;
  catGroup.add(leftEar);
  const rightEar = new THREE.Mesh(earGeo, furMat);
  rightEar.position.set(0.35, 1.35, 0.1);
  rightEar.rotation.z = -0.25;
  catGroup.add(rightEar);

  // 耳朵内侧
  const earInnerGeo = new THREE.ConeGeometry(0.18, 0.35, 8);
  const leftEarInner = new THREE.Mesh(earInnerGeo, earInnerMat);
  leftEarInner.position.set(-0.35, 1.28, 0.25);
  leftEarInner.rotation.z = 0.25;
  catGroup.add(leftEarInner);
  const rightEarInner = new THREE.Mesh(earInnerGeo, earInnerMat);
  rightEarInner.position.set(0.35, 1.28, 0.25);
  rightEarInner.rotation.z = -0.25;
  catGroup.add(rightEarInner);

  // 眼睛
  const eyeGeo = new THREE.SphereGeometry(0.12, 16, 12);
  const leftEye = new THREE.Mesh(eyeGeo, eyeMat);
  leftEye.position.set(-0.25, 1.0, 0.6);
  catGroup.add(leftEye);
  const rightEye = new THREE.Mesh(eyeGeo, eyeMat);
  rightEye.position.set(0.25, 1.0, 0.6);
  catGroup.add(rightEye);

  // 眼睛高光
  const highlightGeo = new THREE.SphereGeometry(0.05, 8, 6);
  const leftHL = new THREE.Mesh(highlightGeo, eyeWhiteMat);
  leftHL.position.set(-0.23, 1.05, 0.68);
  catGroup.add(leftHL);
  const rightHL = new THREE.Mesh(highlightGeo, eyeWhiteMat);
  rightHL.position.set(0.27, 1.05, 0.68);
  catGroup.add(rightHL);

  // 鼻子
  const noseGeo = new THREE.SphereGeometry(0.08, 12, 8);
  const nose = new THREE.Mesh(noseGeo, noseMat);
  nose.position.set(0, 0.85, 0.62);
  nose.scale.set(1, 0.7, 0.5);
  catGroup.add(nose);

  // 嘴巴
  const mouthLeftGeo = new THREE.TorusGeometry(0.06, 0.015, 8, 8, Math.PI);
  const mouthLeft = new THREE.Mesh(mouthLeftGeo, mouthMat);
  mouthLeft.position.set(-0.08, 0.79, 0.62);
  mouthLeft.rotation.z = Math.PI * 0.15;
  catGroup.add(mouthLeft);
  const mouthRightGeo = new THREE.TorusGeometry(0.06, 0.015, 8, 8, Math.PI);
  const mouthRight = new THREE.Mesh(mouthRightGeo, mouthMat);
  mouthRight.position.set(0.08, 0.79, 0.62);
  mouthRight.rotation.z = Math.PI * 0.85;
  catGroup.add(mouthRight);

  // 胡须 (细线)
  function addWhisker(x, y, z, rx, ry, rz) {
    const whiskerGeo = new THREE.CylinderGeometry(0.015, 0.015, 0.4, 6);
    const whisker = new THREE.Mesh(whiskerGeo, new THREE.MeshStandardMaterial({ color: 0xdddddd }));
    whisker.position.set(x, y, z);
    whisker.rotation.set(rx, ry, rz);
    catGroup.add(whisker);
  }
  addWhisker(-0.3, 0.85, 0.55, 0.1, 0.3, -0.2);
  addWhisker(-0.3, 0.8, 0.55, 0, 0.2, -0.1);
  addWhisker(0.3, 0.85, 0.55, 0.1, -0.3, 0.2);
  addWhisker(0.3, 0.8, 0.55, 0, -0.2, 0.1);

  // 前腿
  function addLeg(x, z, front) {
    const legGeo = new THREE.CylinderGeometry(0.18, 0.22, 0.7, 12);
    const leg = new THREE.Mesh(legGeo, furMat);
    leg.position.set(x, -0.55, z);
    if (front) leg.position.z += 0.25;
    catGroup.add(leg);
    // 爪子
    const pawGeo = new THREE.SphereGeometry(0.2, 12, 8);
    const paw = new THREE.Mesh(pawGeo, pawMat);
    paw.position.set(x, -0.9, z + (front ? 0.25 : 0));
    paw.scale.set(1, 0.4, 1);
    catGroup.add(paw);
    return { leg, paw };
  }
  const legs = {
    frontLeft: addLeg(-0.4, 0.15, true),
    frontRight: addLeg(0.4, 0.15, true),
    backLeft: addLeg(-0.35, -0.4, false),
    backRight: addLeg(0.35, -0.4, false),
  };

  // 尾巴
  const tailGroup = new THREE.Group();
  tailGroup.position.set(0, -0.35, -0.6);
  const tailSegments = [];
  for (let i = 0; i < 6; i++) {
    const segGeo = new THREE.SphereGeometry(0.12 - i * 0.015, 8, 6);
    const seg = new THREE.Mesh(segGeo, tailMat);
    seg.position.y = i * 0.2;
    tailGroup.add(seg);
    tailSegments.push(seg);
  }
  catGroup.add(tailGroup);

  // 缩放整个猫到合适大小
  catGroup.scale.setScalar(80);
  catGroup.position.y = 40;

  return { group: catGroup, legs, tailGroup, tailSegments, head };
}

// ====================== 状态 ======================
const state = {
  catData: null,
  mode: "idle", modeUntil: 0, walkTarget: W * 0.5, facingDir: 1,
  hover: false, dragging: false, dragOffset: { x: 0, y: 0 }, movedDuringDrag: false,
  happiness: 1.0, cursor: { x: W / 2, y: H / 2 }, muted: false,
  typing: { active: false, lastKey: 0, rate: 0, endsAt: 0 },
