// ====================== 发光底座 ======================
function buildPlatform() {
  const group = new THREE.Group();
  // 阴影椭圆
  const shadowGeo = new THREE.CircleGeometry(0.6, 32);
  const shadow = new THREE.Mesh(shadowGeo, new THREE.MeshBasicMaterial({
    color: 0x000000, transparent: true, opacity: 0.25, side: THREE.DoubleSide
  }));
  shadow.rotation.x = -Math.PI / 2;
  shadow.position.y = -0.05;
  shadow.scale.set(1.3, 0.7, 1);
  group.add(shadow);
  // 发光环
  const ringGeo = new THREE.TorusGeometry(0.55, 0.04, 16, 32);
  const ring = new THREE.Mesh(ringGeo, new THREE.MeshBasicMaterial({ color: 0xffaa44, transparent: true, opacity: 0.5 }));
  ring.rotation.x = -Math.PI / 2;
  ring.position.y = 0.01;
  group.add(ring);
  group.position.y = -1.25;
  return group;
}

// ====================== 几何体猫咪 ======================
function buildCat() {
  const catGroup = new THREE.Group();

  const furMat = new THREE.MeshStandardMaterial({ color: 0xff8c42, roughness: 0.5, metalness: 0.05 });
  const bellyMat = new THREE.MeshStandardMaterial({ color: 0xfff5e6, roughness: 0.6 });
  const earInnerMat = new THREE.MeshStandardMaterial({ color: 0xffbb99, roughness: 0.4 });
  const eyeMat = new THREE.MeshStandardMaterial({ color: 0x111111, roughness: 0.05 });
  const eyeWhiteMat = new THREE.MeshStandardMaterial({ color: 0xffffff, roughness: 0.05 });
  const noseMat = new THREE.MeshStandardMaterial({ color: 0xff7799, roughness: 0.3 });
  const pawMat = new THREE.MeshStandardMaterial({ color: 0xfff5e6, roughness: 0.5 });
  const tailMat = new THREE.MeshStandardMaterial({ color: 0xff7722, roughness: 0.5 });

  // 身体
  const body = new THREE.Mesh(new THREE.SphereGeometry(1, 32, 24), furMat);
  body.scale.set(1.0, 0.7, 0.65);
  catGroup.add(body);

  // 肚皮
  const belly = new THREE.Mesh(new THREE.SphereGeometry(0.65, 24, 18), bellyMat);
  belly.scale.set(0.9, 0.55, 0.45);
  belly.position.set(0, -0.15, 0.42);
  catGroup.add(belly);

  // 头
  const head = new THREE.Mesh(new THREE.SphereGeometry(0.68, 32, 24), furMat);
  head.position.set(0, 0.8, 0.08);
  head.name = "head";
  catGroup.add(head);

  // 脸颊
  for (let s = -1; s <= 1; s += 2) {
    const cheek = new THREE.Mesh(new THREE.SphereGeometry(0.33, 16, 12), bellyMat);
    cheek.position.set(s * 0.42, 0.65, 0.52);
    cheek.scale.set(0.7, 0.55, 0.28);
    catGroup.add(cheek);
  }

  // 耳朵
  for (let s = -1; s <= 1; s += 2) {
    const ear = new THREE.Mesh(new THREE.ConeGeometry(0.28, 0.5, 8), furMat);
    ear.position.set(s * 0.32, 1.28, 0.08);
    ear.rotation.z = s * 0.2;
    catGroup.add(ear);
    const earInner = new THREE.Mesh(new THREE.ConeGeometry(0.16, 0.32, 8), earInnerMat);
    earInner.position.set(s * 0.32, 1.22, 0.22);
    earInner.rotation.z = s * 0.2;
    catGroup.add(earInner);
  }

  // 眼睛 + 高光
  for (let s = -1; s <= 1; s += 2) {
    const eye = new THREE.Mesh(new THREE.SphereGeometry(0.11, 16, 12), eyeMat);
    eye.position.set(s * 0.23, 0.95, 0.58);
    catGroup.add(eye);
    const hl = new THREE.Mesh(new THREE.SphereGeometry(0.045, 8, 6), eyeWhiteMat);
    hl.position.set(s * 0.2, 1.0, 0.65);
    catGroup.add(hl);
  }

  // 鼻子
  const nose = new THREE.Mesh(new THREE.SphereGeometry(0.07, 12, 8), noseMat);
  nose.position.set(0, 0.82, 0.6);
  nose.scale.set(1, 0.65, 0.45);
  catGroup.add(nose);

  // 微笑
  for (let s = -1; s <= 1; s += 2) {
    const mouth = new THREE.Mesh(
      new THREE.TorusGeometry(0.05, 0.012, 8, 8, Math.PI),
      new THREE.MeshStandardMaterial({ color: 0x553322 })
    );
    mouth.position.set(s * 0.07, 0.76, 0.6);
    mouth.rotation.z = s > 0 ? Math.PI * 0.85 : Math.PI * 0.15;
    catGroup.add(mouth);
  }

  // 胡须
  for (let s = -1; s <= 1; s += 2) {
    for (let i = 0; i < 2; i++) {
      const w = new THREE.Mesh(
        new THREE.CylinderGeometry(0.012, 0.012, 0.35, 6),
        new THREE.MeshStandardMaterial({ color: 0xeeeeee })
      );
      w.position.set(s * 0.28, 0.82 - i * 0.05, 0.52);
      w.rotation.set(0.1, s * 0.3, s * -0.15 + i * 0.1);
      catGroup.add(w);
    }
  }

  // 前腿
  function makeLeg(x, z, front) {
    const leg = new THREE.Mesh(new THREE.CylinderGeometry(0.16, 0.2, 0.65, 12), furMat);
    leg.position.set(x, -0.5, z + (front ? 0.22 : 0));
    catGroup.add(leg);
    const paw = new THREE.Mesh(new THREE.SphereGeometry(0.18, 10, 8), pawMat);
    paw.position.set(x, -0.83, z + (front ? 0.22 : 0));
    paw.scale.set(1, 0.35, 1);
    catGroup.add(paw);
    return { leg, paw };
  }
  const legs = {
    fl: makeLeg(-0.38, 0.12, true), fr: makeLeg(0.38, 0.12, true),
    bl: makeLeg(-0.33, -0.38, false), br: makeLeg(0.33, -0.38, false),
  };

  // 尾巴
  const tailGroup = new THREE.Group();
  tailGroup.position.set(0, -0.3, -0.55);
  const tailSegments = [];
  for (let i = 0; i < 6; i++) {
    const seg = new THREE.Mesh(new THREE.SphereGeometry(0.11 - i * 0.014, 8, 6), tailMat);
    seg.position.y = i * 0.18;
    tailGroup.add(seg);
    tailSegments.push(seg);
  }
  catGroup.add(tailGroup);

  // 发光底座
  catGroup.add(buildPlatform());

  // 缩放: 160px (原来的2倍)
  catGroup.scale.setScalar(160);
  catGroup.position.y = 60;

  return { group: catGroup, legs, tailGroup, tailSegments, head };
}

// ====================== 状态机 ======================
const state = {
  catData: null,
