// ====================== 主循环 ======================
const clock = new THREE.Clock();
let lastHDecay = performance.now();

function tick() {
  const now = performance.now();
  const dt = Math.min(clock.getDelta(), 0.1);

  // 启动掉落动画
  if (state.startupAnim) {
    const elapsed = (now - state.startupStart) / 1000;
    if (elapsed < 1.2) {
      // 从上方弹入
      const t = elapsed / 1.2;
      const bounce = Math.abs(Math.sin(t * Math.PI * 3)) * Math.exp(-t * 3) * 300;
      pivot.position.y = H * 0.68 - bounce;
      pivot.scale.setScalar(1 - (1 - t) * 0.3);
    } else {
      state.startupAnim = false;
      pivot.position.y = H * 0.68;
      pivot.scale.setScalar(1);
      scheduleNextMode(now);
    }
  }

  // 幸福衰减
  if (now - lastHDecay > 1000) { lastHDecay = now; state.happiness = Math.max(0, state.happiness - 0.008); applyMood(); }

  // 打字弹跳
  if (state.typing.active && state.mode !== "spin") {
    bob.position.y = Math.abs(Math.sin(now / 70)) * 6;
    if (now >= state.typing.endsAt) {
      state.typing.active = false; state.typing.rate = 0;
      try { audio.pause(); } catch (_) {}
      if (!state.startupAnim) scheduleNextMode(now);
    }
  } else { state.typing.rate *= 0.985; }

  if (state.startupAnim) { renderer.render(scene, camera); requestAnimationFrame(tick); return; }

  // 模式
  if (state.mode === "walk") {
    const dx = state.walkTarget - pivot.position.x;
    state.facingDir = Math.sign(dx) || state.facingDir;
    if (Math.abs(dx) > 2) {
      pivot.position.x += Math.sign(dx) * Math.min(Math.abs(dx), 100 * dt);
      bob.position.y = Math.abs(Math.sin(now / 90)) * 9;
    } else bob.position.y = 0;
    if (now >= state.modeUntil || Math.abs(dx) < 2) scheduleNextMode(now);
  } else if (state.mode === "idle") {
    bob.position.y = Math.sin(now / 550) * 3.5;
    bob.scale.set(1, 1 + Math.sin(now / 550) * 0.02, 1);
    if (now >= state.modeUntil) scheduleNextMode(now);
  } else if (state.mode === "sit") {
    bob.position.y = -8; bob.scale.set(1, 0.88, 1);
    if (now >= state.modeUntil) { bob.scale.set(1, 1, 1); bob.position.y = 0; scheduleNextMode(now); }
  } else if (state.mode === "yawn") {
    const t = 1 - (state.modeUntil - now) / 2000;
    bob.scale.set(1, 1 + Math.sin(Math.min(1, t) * Math.PI) * 0.12, 1);
    if (now >= state.modeUntil) { bob.scale.set(1, 1, 1); scheduleNextMode(now); }
  } else if (state.mode === "spin") {
    facing.rotation.y += dt * 10;
    bob.position.y = Math.sin(now / 80) * 4;
    if (now >= state.modeUntil) {
      facing.rotation.y = 0; bob.position.y = 0;
      try { audio.pause(); } catch (_) {}
      scheduleNextMode(now);
    }
  }

  // 面向
  facing.scale.x += ((state.facingDir >= 0 ? 1 : -1) - facing.scale.x) * Math.min(1, dt * 6);

  // 尾巴
  if (state.catData) {
    state.catData.tailGroup.rotation.y = Math.sin(now / 180) * 0.35;
    state.catData.tailSegments.forEach((s, i) => {
      s.position.x = Math.sin(now / 130 + i * 0.6) * 0.06;
    });
  }

  // 压力测试
  if (state.stressActive) {
    canvas.style.filter = "saturate(" + (0.7 + Math.sin(now / 200) * 0.3) + ") hue-rotate(" + Math.sin(now / 300) * 15 + "deg)";
  }

  updateHover();
  if (now > state.speechTimer) bubbleEl.style.opacity = "0";

  renderer.render(scene, camera);
  requestAnimationFrame(tick);
}

