  else if (r < 0.75) { state.mode = "walk"; state.walkTarget = 100 + Math.random() * (W - 200); state.facingDir = state.walkTarget < pivot.position.x ? -1 : 1; state.modeUntil = now + 5000 + Math.random() * 4000; }
  else if (r < 0.9) { state.mode = "sit"; state.modeUntil = now + 2000 + Math.random() * 2500; }
  else { state.mode = "yawn"; state.modeUntil = now + 1000 + Math.random() * 800; }
}

// ====================== 主循环 ======================
const clock = new THREE.Clock();
let lastHDecay = performance.now();

function tick() {
  const now = performance.now();
  const dt = Math.min(clock.getDelta(), 0.1);

  // 启动掉落动画
  if (state.startupAnim && !state.loading) {
    const elapsed = (now - state.startupStart) / 1000;
    if (elapsed < 1.5) {
      const t = elapsed / 1.5;
      const bounce = Math.abs(Math.sin(t * Math.PI * 3)) * Math.exp(-t * 3) * 350;
      pivot.position.y = H * 0.62 - bounce;
      pivot.scale.setScalar(1 - (1 - t) * 0.25);
    } else {
      state.startupAnim = false;
      pivot.position.y = H * 0.62;
      pivot.scale.setScalar(1);
      scheduleNextMode(now);
    }
  }

  // 动画更新
  if (state.mixer) state.mixer.update(dt);

  // 幸福衰减
  if (now - lastHDecay > 1000) { lastHDecay = now; state.happiness = Math.max(0, state.happiness - 0.006); applyMood(); }

  // 打字弹跳
  if (state.typing.active && state.mode !== "spin") {
    bob.position.y = Math.abs(Math.sin(now / 80)) * 8;
    if (now >= state.typing.endsAt) {
      state.typing.active = false; state.typing.rate = 0;
      try { audio.pause(); } catch (_) {}
      if (!state.startupAnim) scheduleNextMode(now);
    }
  } else { state.typing.rate *= 0.985; }

  if (state.startupAnim || state.loading) { renderer.render(scene, camera); requestAnimationFrame(tick); return; }

  // 行走动画控制
  if (state.mode === "walk" && state.walkAction) {
    if (!state.walkAction.isRunning()) { state.walkAction.reset(); state.walkAction.play(); }
    state.walkAction.timeScale = 1.0;
  } else if (state.walkAction && state.walkAction.isRunning()) {
    if (state.mode !== "spin") state.walkAction.stop();
  }

  // 待机动画
  if (state.mode === "idle" && state.idleAction && !state.idleAction.isRunning()) {
    state.idleAction.reset(); state.idleAction.play();
  }

  // 模式
  if (state.mode === "walk") {
    const dx = state.walkTarget - pivot.position.x;
    state.facingDir = Math.sign(dx) || state.facingDir;
    if (Math.abs(dx) > 2) {
      pivot.position.x += Math.sign(dx) * Math.min(Math.abs(dx), 120 * dt);
      bob.position.y = Math.abs(Math.sin(now / 100)) * 10;
    } else bob.position.y = 0;
    if (now >= state.modeUntil || Math.abs(dx) < 2) scheduleNextMode(now);
  } else if (state.mode === "idle") {
    bob.position.y = Math.sin(now / 700) * 3;
    if (now >= state.modeUntil) scheduleNextMode(now);
  } else if (state.mode === "sit") {
    bob.position.y = -15; bob.scale.set(1, 0.85, 1);
    if (now >= state.modeUntil) { bob.scale.set(1, 1, 1); bob.position.y = 0; scheduleNextMode(now); }
  } else if (state.mode === "yawn") {
    const t = 1 - (state.modeUntil - now) / 2000;
    bob.scale.set(1, 1 + Math.sin(Math.min(1, t) * Math.PI) * 0.08, 1);
    if (now >= state.modeUntil) { bob.scale.set(1, 1, 1); scheduleNextMode(now); }
  } else if (state.mode === "spin") {
    facing.rotation.y += dt * 6;
    bob.position.y = Math.sin(now / 90) * 5;
    if (now >= state.modeUntil) {
      facing.rotation.y = 0; bob.position.y = 0;
      if (state.spinAction) state.spinAction.stop();
      try { audio.pause(); } catch (_) {}
      scheduleNextMode(now);
    }
  }

  // 面向
  facing.scale.x += ((state.facingDir >= 0 ? 1 : -1) - facing.scale.x) * Math.min(1, dt * 5);

  // 压力测试
  if (state.stressActive) {
    canvas.style.filter = "saturate(" + (0.7 + Math.sin(now / 200) * 0.3) + ") hue-rotate(" + Math.sin(now / 300) * 15 + "deg)";
  }

  updateHover();
  if (now > state.speechTimer) bubbleEl.style.opacity = "0";

  renderer.render(scene, camera);
  requestAnimationFrame(tick);
}

// ====================== 启动 ======================
initVoiceRecognition();
tick();
applyMood();

