function fmtBytes(bytes: number): string {
  if (bytes === 0) return "0 Bytes";
  const k = 1024;
  const sizes = ["Bytes", "KB", "MB", "GB"];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + " " + sizes[i];
}

// ═══════════════════════════════════════
// 原生 JSON-RPC 传输层
// ═══════════════════════════════════════

const SERVER_INFO = { name: "gbt-xiaotudou-native-mcp", version: "2.0.0" };

function send(res: JsonRpcResponse) {
  process.stdout.write(JSON.stringify(res) + "\n");
}

function errorResponse(id: number | string, code: number, message: string): JsonRpcResponse {
  return { jsonrpc: "2.0", id, error: { code, message } };
}

async function handleRequest(req: JsonRpcRequest): Promise<void> {
  const { id, method, params } = req;

  try {
    switch (method) {
      case "initialize": {
        send({ jsonrpc: "2.0", id, result: { protocolVersion: "2024-11-05", capabilities: { tools: {} }, serverInfo: SERVER_INFO } });
        return;
      }

      case "notifications/initialized": {
        // 无需响应，notifications 不期待回复
        return;
      }

      case "tools/list": {
        const toolList = Array.from(tools.values()).map(t => t.def);
        send({ jsonrpc: "2.0", id, result: { tools: toolList } });
        return;
      }

      case "tools/call": {
        const { name, arguments: toolArgs } = (params || {}) as { name?: string; arguments?: Record<string, unknown> };
        if (!name) {
          send(errorResponse(id, -32602, "Missing tool name"));
          return;
        }
        const entry = tools.get(name);
        if (!entry) {
          send(errorResponse(id, -32601, `Unknown tool: ${name}`));
          return;
        }
        try {
          const result = await entry.handler(toolArgs || {});
          send({ jsonrpc: "2.0", id, result });
        } catch (e: any) {
          send({ jsonrpc: "2.0", id, result: { content: [{ type: "text", text: `Error: ${e.message}` }], isError: true } });
        }
        return;
      }

      case "ping": {
        send({ jsonrpc: "2.0", id, result: {} });
        return;
      }

      default:
        send(errorResponse(id, -32601, `Method not found: ${method}`));
    }
  } catch (e: any) {
    send(errorResponse(id, -32603, `Internal error: ${e.message}`));
  }
}

