rl.on("line", (line: string) => {
  line = line.trim();
  if (!line) return;
  try {
    const req: JsonRpcRequest = JSON.parse(line);
    if (req.jsonrpc !== "2.0" || req.id === undefined) return;
    handleRequest(req);
  } catch {
    // 忽略无效 JSON
  }
});

