$code = @'
/**
 * GBT Native File System — 零依赖文件操作
 * 简洁、原生、不误拦 Windows 路径
 */
import * as fs from "node:fs";
import * as path from "node:path";
import { readFile, writeFile, mkdir, readdir, unlink, stat } from "node:fs/promises";

// ═══════════════════════════════════════
// 唯一保护: 禁止删除/写入系统关键路径
// ═══════════════════════════════════════

const CRITICAL_PATHS = [
  "C:\\Windows\\System32",
  "C:\\Windows\\System",
  "C:\\Windows\\boot",
  "/etc/passwd",
  "/etc/shadow",
  "/etc/sudoers",
  "/etc/ssh",
];

function isCriticalPath(fp: string): boolean {
  const norm = path.resolve(fp).toLowerCase();
  return CRITICAL_PATHS.some(p => norm.startsWith(p.toLowerCase()));
}

// ═══════════════════════════════════════
// 公开 API (与旧模块签名兼容)
// ═══════════════════════════════════════

export async function isFileSafe(fp: string): Promise<boolean> {
  try {
    const norm = path.resolve(fp);
    // 只拦截真危险的
    if (isCriticalPath(norm)) return false;
    // 路径遍历检测
    if (norm.includes("..")) return false;
    return true;
  } catch {
    return false;
  }
}

export async function secureReadFile(
  fp: string,
  _role?: string,
  _userId?: string
): Promise<string> {
  if (!(await isFileSafe(fp))) throw new Error(`路径不安全: ${fp}`);
  if (!fs.existsSync(fp)) throw new Error(`文件不存在: ${fp}`);
  return readFile(fp, "utf-8");
}

export async function secureWriteFile(
  fp: string,
  content: string,
  _role?: string,
  _userId?: string
): Promise<void> {
  if (!(await isFileSafe(fp))) throw new Error(`路径不安全: ${fp}`);
  if (isCriticalPath(fp)) throw new Error(`禁止写入系统关键路径: ${fp}`);
  await mkdir(path.dirname(fp), { recursive: true });
  await writeFile(fp, content, "utf-8");
}

export async function secureDeleteFile(
  fp: string,
  _role?: string,
  _userId?: string
): Promise<void> {
  if (!(await isFileSafe(fp))) throw new Error(`路径不安全: ${fp}`);
  if (isCriticalPath(fp)) throw new Error(`禁止删除系统关键路径: ${fp}`);
  if (!fs.existsSync(fp)) throw new Error(`文件不存在: ${fp}`);
  await unlink(fp);
}

export async function secureListDirectory(
  dirPath: string,
  _role?: string,
  _userId?: string
): Promise<Array<{ name: string; path: string; isDirectory: boolean; size?: number }>> {
  if (!(await isFileSafe(dirPath))) throw new Error(`路径不安全: ${dirPath}`);
  if (!fs.existsSync(dirPath)) throw new Error(`目录不存在: ${dirPath}`);
  const entries = await readdir(dirPath, { withFileTypes: true });
  const result = [];
  for (const entry of entries) {
    const fullPath = path.join(dirPath, entry.name);
    let size: number | undefined;
    try {
      const st = await stat(fullPath);
      size = st.isFile() ? st.size : undefined;
    } catch { /* skip */ }
    result.push({
      name: entry.name,
      path: fullPath,
      isDirectory: entry.isDirectory(),
      size,
    });
  }
  return result;
}

// 保留旧导出名 (兼容)
export { isFileSafe as validatePath };
'@

